import json
import pandas as pd
import os

# Check all available variables
all_vars = list(locals().keys())
print('Available variables:', all_vars[:20])

# Look for the books data
books_data = None
for key in all_vars:
    val = locals()[key]
    if isinstance(val, list) and len(val) > 0:
        if isinstance(val[0], dict) and 'categories' in val[0]:
            books_data = val
            print('Found books data in variable:', key)
            break

# Look for the reviews data  
reviews_data = None
for key in all_vars:
    val = locals()[key]
    if isinstance(val, list) and len(val) > 0:
        if isinstance(val[0], dict) and 'rating' in val[0] and 'purchase_id' in val[0]:
            reviews_data = val
            print('Found reviews data in variable:', key)
            break

# Also check if reviews are in a file
if reviews_data is None:
    # Try to find JSON file paths
    for key in all_vars:
        val = locals()[key]
        if isinstance(val, str) and val.endswith('.json') and os.path.exists(val):
            try:
                with open(val, 'r') as f:
                    data = json.load(f)
                    if isinstance(data, list) and len(data) > 0 and 'rating' in data[0]:
                        reviews_data = data
                        print('Found reviews in file:', val)
                        break
            except:
                pass

print('__RESULT__:')
print(json.dumps({
    'books_count': len(books_data) if books_data else 0,
    'reviews_count': len(reviews_data) if reviews_data else 0,
    'sample_book': books_data[0] if books_data else None
}))

