import json
import os

# The variables contain file paths, let's try to find the actual files
# Based on the pattern, these might be stored as actual file paths in the variables

# Let's check all the variables to find which ones contain the file paths
all_vars = locals()

books_file_path = None
reviews_file_path = None

# Look specifically for our query results
for var_name, var_value in all_vars.items():
    if isinstance(var_value, str) and 'query_db:42' in var_value:
        books_file_path = var_value
    elif isinstance(var_name, str) and 'query_db:42' in var_name:
        books_file_path = var_value
    elif isinstance(var_value, str) and 'query_db' in var_value and ('books' in var_value or 'bookid' in var_value):
        books_file_path = var_value

    if isinstance(var_value, str) and 'query_db:43' in var_value:
        reviews_file_path = var_value
    elif isinstance(var_name, str) and 'query_db:43' in var_name:
        reviews_file_path = var_value
    elif isinstance(var_value, str) and 'query_db' in var_value and ('purchase' in var_value or 'rating' in var_value):
        reviews_file_path = var_value

print('Books file path found:', books_file_path)
print('Reviews file path found:', reviews_file_path)

# List all JSON files in current directory to find the data
json_files = [f for f in os.listdir('.') if f.endswith('.json')]
print('JSON files in directory:', json_files)

books_data = []
reviews_data = []

# Try loading from the files
for file in json_files:
    try:
        with open(file, 'r') as f:
            data = json.load(f)
            if isinstance(data, list) and len(data) > 0:
                if isinstance(data[0], dict):
                    if 'book_id' in data[0]:
                        books_data = data
                        print(f'Loaded {len(books_data)} books from {file}')
                    elif 'rating' in data[0] and 'purchase_id' in data[0]:
                        reviews_data = data
                        print(f'Loaded {len(reviews_data)} reviews from {file}')
    except Exception as e:
        print(f'Error loading {file}: {e}')

print('__RESULT__:')
print(json.dumps({
    'books': len(books_data),
    'reviews': len(reviews_data),
    'sample_book': books_data[0] if books_data else None,
    'sample_review': reviews_data[0] if reviews_data else None
}))

